namespace sv_d4f998546f8240fabc6aa26ec4a2fc6a.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Step progress indicator bar with clickable completed steps *@

<nav class="step-indicator" aria-label="Application progress">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var css = step == CurrentStep ? "step active"
                : CompletedSteps.Contains(step) ? "step completed"
                : "step dimmed";

        <button class="@css"
                disabled="@(!CompletedSteps.Contains(step) && step != CurrentStep)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (CompletedSteps.Contains(step) && step != CurrentStep)
                {
                    <span class="checkmark">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (i < StepNames.Length - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")"></span>
        }
    }
</nav>

@code {
    private static readonly string[] StepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 0;
    padding: 1.5rem 0;
    margin-bottom: 2rem;
    flex-wrap: wrap;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    background: none;
    border: none;
    cursor: default;
    padding: 0.5rem;
    min-width: 100px;
    transition: all 0.2s ease;
}

.step.completed {
    cursor: pointer;
}

.step.completed:hover .step-number {
    background-color: #0a58ca;
    transform: scale(1.1);
}

.step-number {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.9rem;
    transition: all 0.2s ease;
}

.step.active .step-number {
    background-color: #0d6efd;
    color: white;
}

.step.completed .step-number {
    background-color: #198754;
    color: white;
}

.step.dimmed .step-number {
    background-color: #dee2e6;
    color: #6c757d;
}

.step-label {
    font-size: 0.8rem;
    text-align: center;
    white-space: nowrap;
}

.step.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step.dimmed .step-label {
    color: #adb5bd;
}

.step-connector {
    flex: 0 0 40px;
    height: 2px;
    background-color: #dee2e6;
    margin-bottom: 1.5rem;
}

.step-connector.completed {
    background-color: #198754;
}

.checkmark {
    font-size: 1rem;
}

@* Single work history entry form *@

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-start mb-3">
            <h6 class="card-title mb-0">Position @(Index + 1)</h6>
            @if (CanRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">
                    Remove
                </button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input class="form-control" value="@Company" @onchange="e => { Company = e.Value?.ToString() ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input class="form-control" value="@Title" @onchange="e => { Title = e.Value?.ToString() ?? ""; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date <span class="text-danger">*</span></label>
                <input type="date" class="form-control" value="@StartDate?.ToString("yyyy-MM-dd")"
                       @onchange="e => { StartDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@EndDate?.ToString("yyyy-MM-dd")"
                       disabled="@IsCurrent"
                       @onchange="e => { EndDate = DateTime.TryParse(e.Value?.ToString(), out var d) ? d : null; NotifyChanged(); }" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input class="form-check-input" type="checkbox" id="current-@Index" checked="@IsCurrent"
                           @onchange="e => { IsCurrent = (bool)(e.Value ?? false); if (IsCurrent) EndDate = null; NotifyChanged(); }" />
                    <label class="form-check-label" for="current-@Index">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Description"
                          @onchange="e => { Description = e.Value?.ToString() ?? ""; NotifyChanged(); }"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter] public string Company { get; set; } = "";
    [Parameter] public string Title { get; set; } = "";
    [Parameter] public DateTime? StartDate { get; set; }
    [Parameter] public DateTime? EndDate { get; set; }
    [Parameter] public bool IsCurrent { get; set; }
    [Parameter] public string Description { get; set; } = "";
    [Parameter] public EventCallback<WorkEntryData> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void NotifyChanged()
    {
        OnChanged.InvokeAsync(new WorkEntryData(Company, Title, StartDate, EndDate, IsCurrent, Description));
    }

    public record WorkEntryData(string Company, string Title, DateTime? StartDate, DateTime? EndDate, bool IsCurrent, string Description);
}

