<h4 class="mb-4">Review Your Application</h4>

@* Personal Info *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Name</dt><dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt><dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt><dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt><dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

@* Work History *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @entry.StartDate?.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

@* References *@
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> — @r.Relationship<br />
                <span class="text-muted">@r.Email · @r.Phone</span>
            </div>
        }
    </div>
</div>

@* Cover Letter *@
<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <text>Submitting…</text>
        }
        else
        {
            <text>Submit Application</text>
        }
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkHistoryStep.EntryModel> WorkEntries { get; set; } = [];
    [Parameter, EditorRequired] public List<ReferencesStep.RefModel> References { get; set; } = [];
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool IsSubmitting;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

