@using sv_d4f998546f8240fabc6aa26ec4a2fc6a.Models

<h4 class="mb-4">Work History</h4>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <WorkEntryForm Index="index"
                   CanRemove="Entries.Count > 1"
                   Company="@entry.Company"
                   Title="@entry.Title"
                   StartDate="@entry.StartDate"
                   EndDate="@entry.EndDate"
                   IsCurrent="@entry.IsCurrent"
                   Description="@entry.Description"
                   OnChanged="data => UpdateEntry(index, data)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="() => OnBack.InvokeAsync()">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<EntryModel> Entries { get; set; } = [new()];
    [Parameter] public EventCallback<List<EntryModel>> OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Entries.Add(new EntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private void UpdateEntry(int index, WorkEntryForm.WorkEntryData data)
    {
        Entries[index] = new EntryModel
        {
            Company = data.Company,
            Title = data.Title,
            StartDate = data.StartDate,
            EndDate = data.EndDate,
            IsCurrent = data.IsCurrent,
            Description = data.Description
        };
    }

    private Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate is null)
            {
                ErrorMessage = "Company, job title, and start date are required for each position.";
                return Task.CompletedTask;
            }
        }

        return OnNext.InvokeAsync(new List<EntryModel>(Entries));
    }

    public class EntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime? StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";

        public WorkEntry ToRecord() =>
            new(Company.Trim(), Title.Trim(), StartDate!.Value, IsCurrent ? null : EndDate, Description.Trim());
    }
}

