    @if (SubmittedId is not null)
    {
        <div class="text-center py-5">
            <div class="mb-4">
                <span style="font-size: 4rem; color: #198754;">✓</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@SubmittedId</strong>.</p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="CurrentStep" CompletedSteps="CompletedSteps" OnStepClicked="GoToStep" />

        @switch (CurrentStep)
        {
            case 0:
                <PersonalInfoStep FullName="@PersonalFullName"
                                  Email="@PersonalEmail"
                                  Phone="@PersonalPhone"
                                  Address="@PersonalAddress"
                                  ApplicationService="ApplicationService"
                                  OnNext="HandlePersonalNext" />
                break;

            case 1:
                <WorkHistoryStep Entries="WorkEntries" OnNext="HandleWorkNext" OnBack="GoBack" />
                break;

            case 2:
                <ReferencesStep References="ReferenceEntries" OnNext="HandleReferencesNext" OnBack="GoBack" />
                break;

            case 3:
                <CoverLetterStep CoverLetterText="@CoverLetterText" OnNext="HandleCoverLetterNext" OnBack="GoBack" />
                break;

            case 4:
                <ReviewStep Personal="@GetPersonalInfo()"
                            WorkEntries="WorkEntries"
                            References="ReferenceEntries"
                            CoverLetter="@CoverLetterText"
                            OnEditStep="GoToStep"
                            OnBack="GoBack"
                            OnSubmit="HandleSubmit" />
                break;
        }
    }
</div>

@code {
    private int CurrentStep;
    private HashSet<int> CompletedSteps = [];
    private int? SubmittedId;

    // Step 1 state
    private string PersonalFullName = "";
    private string PersonalEmail = "";
    private string PersonalPhone = "";
    private string PersonalAddress = "";

    // Step 2 state
    private List<WorkHistoryStep.EntryModel> WorkEntries = [new()];

    // Step 3 state
    private List<ReferencesStep.RefModel> ReferenceEntries = [new(), new()];

    // Step 4 state
    private string CoverLetterText = "";

    private PersonalInfo GetPersonalInfo() =>
        new(PersonalFullName, PersonalEmail, PersonalPhone, PersonalAddress);

    private void HandlePersonalNext(PersonalInfo info)
    {
        PersonalFullName = info.FullName;
        PersonalEmail = info.Email;
        PersonalPhone = info.Phone;
        PersonalAddress = info.Address;
        CompletedSteps.Add(0);
        CurrentStep = 1;
    }

    private void HandleWorkNext(List<WorkHistoryStep.EntryModel> entries)
    {
        WorkEntries = entries;
        CompletedSteps.Add(1);
        CurrentStep = 2;
    }

    private void HandleReferencesNext(List<ReferencesStep.RefModel> refs)
    {
        ReferenceEntries = refs;
        CompletedSteps.Add(2);
        CurrentStep = 3;
    }

    private void HandleCoverLetterNext(string text)
    {
        CoverLetterText = text;
        CompletedSteps.Add(3);
        CurrentStep = 4;
    }

    private async Task HandleSubmit()
    {
        var application = new JobApplication(
            GetPersonalInfo(),
            new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
            ReferenceEntries.Select(r => r.ToRecord()).ToList(),
            CoverLetterText
        );

        SubmittedId = await ApplicationService.SubmitApplicationAsync(application);
    }

    private void GoToStep(int step)
    {
        if (CompletedSteps.Contains(step) || step == CurrentStep)
        {
            CurrentStep = step;
        }
    }

    private void GoBack()
    {
        if (CurrentStep > 0) CurrentStep--;
    }
}

