+    private void HandleReferencesNext(List<ReferencesStep.RefModel> refs)
+    {
+        ReferenceEntries = refs;
+        CompletedSteps.Add(2);
+        CurrentStep = 3;
+    }
+
+    private void HandleCoverLetterNext(string text)
+    {
+        CoverLetterText = text;
+        CompletedSteps.Add(3);
+        CurrentStep = 4;
+    }
+
+    private async Task HandleSubmit()
+    {
+        var application = new JobApplication(
+            GetPersonalInfo(),
+            new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
+            ReferenceEntries.Select(r => r.ToRecord()).ToList(),
+            CoverLetterText
+        );
+
+        SubmittedId = await ApplicationService.SubmitApplicationAsync(application);
+    }
+
+    private void GoToStep(int step)
+    {
+        if (CompletedSteps.Contains(step) || step == CurrentStep)
+        {
+            CurrentStep = step;
+        }
+    }
+
+    private void GoBack()
+    {
+        if (CurrentStep > 0) CurrentStep--;
+    }
+}
